using namespace std;

const int MAX_SIEVE = 1000000;

vector<int> get_prime_factors(long long x, vector<bool>& is_prime);

long long solve(vector<long long> nums) {
    int n = nums.size();
    if (n == 0) return 0;
    // Precompute sieve
    vector<bool> is_prime(MAX_SIEVE + 1, true);
    is_prime[0] = is_prime[1] = false;
    for (int i = 2; i * i <= MAX_SIEVE; ++i) {
        if (is_prime[i]) {
            for (int j = i * i; j <= MAX_SIEVE; j += i) {
                is_prime[j] = false;
            }
        }
    }

    // Preprocess prime indices
    unordered_map<int, vector<int>> prime_indices;
    for (int i = 0; i < n; ++i) {
        long long x = nums[i];
        vector<int> factors = get_prime_factors(x, is_prime);
        for (int p : factors) {
            prime_indices[p].push_back(i);
        }
    }

    // BFS
    vector<int> distance(n, -1);
    distance[0] = 0;
    queue<int> q;
    q.push(0);

    while (!q.empty()) {
        int current = q.front();
        q.pop();
        if (current == n - 1) return distance[current];
        // Check adjacent
        for (int next : {current - 1, current + 1}) {
            if (next >= 0 && next < n && distance[next] == -1) {
                distance[next] = distance[current] + 1;
                q.push(next);
            }
        }
        // Check teleportation
        long long current_num = nums[current];
        if (is_prime[current_num]) {
            auto& p_list = prime_indices[current_num];
            for (int j : p_list) {
                if (j != current && distance[j] == -1) {
                    distance[j] = distance[current] + 1;
                    q.push(j);
                }
            }
        }
    }
    return -1;
}

vector<int> get_prime_factors(long long x, vector<bool>& is_prime) {
    vector<int> factors;
    if (x == 1) return factors;
    // Check for 2
    if (x % 2 == 0) {
        factors.push_back(2);
        while (x % 2 == 0) x /= 2;
    }
    // Check for odd numbers
    for (int i = 3; i * i <= x; i += 2) {
        if (x % i == 0) {
            factors.push_back(i);
            while (x % i == 0) x /= i;
        }
    }
    if (x > 1) {
        factors.push_back(x);
    }
    return factors;
}
