    const int sieve_max = 1000000;

    // Precompute sieve of Eratosthenes up to sieve_max

    vector<bool> is_prime(sieve_max + 1, true);

    is_prime[0] = is_prime[1] = false;

    for (int i = 2; i * i <= sieve_max; ++i) {

        if (is_prime[i]) {

            for (int j = i * i; j <= sieve_max; j += i) {

                is_prime[j] = false;

            }

        }

    }

    // Now, for each number in nums, find its prime factors

    map<int, vector<int>> prime_indices;

    for (int i = 0; i < n; ++i) {

        long long x = nums[i];

        vector<int> factors;

        // Compute factors of x

        if (x % 2 == 0) {

            factors.push_back(2);

            while (x % 2 == 0) x /= 2;

        }

        long long temp = x;

        for (long long j = 3; j * j <= temp; j += 2) {

            if (temp % j == 0) {

                factors.push_back(j);

                while (temp % j == 0) temp /= j;

            }

        }

        if (temp > 1) {

            factors.push_back(static_cast<int>(temp));

        }

        for (int p : factors) {

            prime_indices[p].push_back(i);

        }

    }

    // BFS

    vector<int> distance(n, -1);

    queue<int> q;

    distance[0] = 0;

    q.push(0);

    while (!q.empty()) {

        int current = q.front();

